prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?language ?exampleModelName WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(?orgId = "c41660388a04449a995dccf97d894f46")

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?defs tai:belongsTo ?model .
  ?defs bboExt:typeLanguage ?language .

  OPTIONAL {
    FILTER(CONTAINS(STR(?language), ""))
    BIND(?modelName AS ?exampleModelName)
  }
}
ORDER BY ?language

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?typeLanguage ?expressionLanguage ?exampleModel WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(?orgId = "c41660388a04449a995dccf97d894f46")

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?exampleModel .

  ?defs tai:belongsTo ?model .
  OPTIONAL { ?defs bboExt:typeLanguage ?typeLanguage . }
  OPTIONAL { ?defs bboExt:expressionLanguage ?expressionLanguage . }
}
ORDER BY ?typeLanguage ?expressionLanguage ?exampleModel
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?typeLanguage ?expressionLanguage ?exporter ?exporterVersion (COUNT(DISTINCT ?model) AS ?modelCount) WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(?orgId = "c41660388a04449a995dccf97d894f46")

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?defs tai:belongsTo ?model .
  OPTIONAL { ?defs bboExt:typeLanguage ?typeLanguage . }
  OPTIONAL { ?defs bboExt:expressionLanguage ?expressionLanguage . }
  OPTIONAL { ?defs bboExt:exporter ?exporter . }
  OPTIONAL { ?defs bboExt:exporterVersion ?exporterVersion . }
}
GROUP BY ?typeLanguage ?expressionLanguage ?exporter ?exporterVersion
ORDER BY DESC(?modelCount)
